// Obtém os tempos configurados para cada follow-up (em minutos)
const tempos = $('Formatar').first().json;
const tempoFollowUp1 = parseInt(tempos.tempo_followUp1, 10);
const tempoFollowUp2 = parseInt(tempos.tempo_followUp2, 10);
const tempoFollowUp3 = parseInt(tempos.tempo_followUp3, 10);

// Captura o timestamp do nó 'Schedule Trigger'
const scheduleTrigger = $('Executa Fluxo').first().json;
const now = new Date(scheduleTrigger.timestamp);

// Função utilitária para calcular diferença em minutos entre duas datas
const calcularDiferencaMinutos = (dataInicio, dataFim) => {
  return Math.floor((dataFim - dataInicio) / (1000 * 60));
};

// Processa os clientes do nó 'Retorna os Pacientes'
const clientes = $('Retorna os Pacientes').all();
const resultado = clientes.map((item) => {
  const cliente = item.json;

  // Validações iniciais (Nome e Número obrigatórios)
  if (!cliente.nome || !cliente.numero) {
    return {
      ...cliente,
      followup: 0
    };
  }

  // Verifica se a última atividade está presente e válida
  const ultimaAtividade = new Date(cliente["ultima_atividade"]);
  if (isNaN(ultimaAtividade.getTime())) {
    return {
      ...cliente,
      followup: 0
    };
  }

  // Calcula o tempo de inatividade em minutos
  const inactivityMinutes = calcularDiferencaMinutos(ultimaAtividade, now);

  // --- LÓGICA DE HIERARQUIA DE FOLLOW-UPS ---

  // 1. Se ainda não deu o tempo do primeiro follow-up
  if (inactivityMinutes < tempoFollowUp1) {
    return { ...cliente, followup: 0 };
  }

  // 2. Zona do Follow-up 1
  if (inactivityMinutes >= tempoFollowUp1 && inactivityMinutes < tempoFollowUp2) {
    // Verifica se JÁ FOI enviado (lê a coluna 'followup1' do banco)
    if (cliente["followup1"] === "sim") {
      return { ...cliente, followup: 0 };
    }
    // Marca como sim para passar para o próximo node atualizar o banco
    cliente["followup1"] = "sim";
    return { ...cliente, followup: 1 };
  }

  // 3. Zona do Follow-up 2
  if (inactivityMinutes >= tempoFollowUp2 && inactivityMinutes < tempoFollowUp3) {
    // Verifica se JÁ FOI enviado (lê a coluna 'followup2' do banco)
    if (cliente["followup2"] === "sim") {
      return { ...cliente, followup: 0 };
    }
    // Marca como sim para passar para o próximo node atualizar o banco
    cliente["followup2"] = "sim";
    return { ...cliente, followup: 2 };
  }

  // 4. Zona do Follow-up 3 (Final)
  if (inactivityMinutes >= tempoFollowUp3) {
    // Verifica se JÁ FOI enviado (lê a coluna 'followup3' do banco)
    if (cliente["followup3"] === "sim") {
      return { ...cliente, followup: 0 };
    }
    // Marca como sim para passar para o próximo node atualizar o banco
    cliente["followup3"] = "sim";
    return { ...cliente, followup: 3 };
  }

  // Caso nenhum follow-up seja aplicável (ex: erro de cálculo ou fora das faixas)
  return { ...cliente, followup: 0 };
});

// Retorna o resultado final
return resultado;

